# label_dataset.py
import pandas as pd
import os

# Use the log file generated by your main supervisor
INPUT_LOG_FILE = 'final_supervisor_log.csv'
OUTPUT_LABELED_FILE = 'labeled_dataset.csv'

# Define the "correct answer" for each scenario
label_map = {
    "Good GPS": 0.9,
    "GPS Jamming": 0.2,
    "High Vibration": 0.1
}

# Check if the input file exists before trying to read it
if not os.path.exists(INPUT_LOG_FILE):
    print(f"ERROR: Input file not found! Please run main_supervisor.py first to create '{INPUT_LOG_FILE}'.")
else:
    print(f"Reading data from {INPUT_LOG_FILE}...")
    df = pd.read_csv(INPUT_LOG_FILE)

    print("Generating target scores based on scenario...")
    # This assumes your log file has a 'scenario' column
    if 'scenario' in df.columns:
        df['target_trust_score'] = df['scenario'].map(label_map)
        df.dropna(subset=['target_trust_score'], inplace=True)
        df.drop(columns=['scenario'], inplace=True)

        print(f"Saving labeled dataset to {OUTPUT_LABELED_FILE}...")
        df.to_csv(OUTPUT_LABELED_FILE, index=False)
        print("Labeling complete!")
    else:
        print("ERROR: Could not find a 'scenario' column in the log file.")